import{bQ as d,aL as e,u as o,G as a}from"./chunks/framework.D06dwy5q.js";const s=JSON.parse('{"title":"一次访问网站","description":"","frontmatter":{},"headers":[],"relativePath":"00.互联网与架构基础/01-一次访问网站.md","filePath":"00.互联网与架构基础/01-一次访问网站.md","lastUpdated":null}'),r={name:"00.互联网与架构基础/01-一次访问网站.md"};function c(E,t,p,A,i,h){return e(),o("div",null,[...t[0]||(t[0]=[a('<h1 id="一次访问网站" tabindex="-1">一次访问网站 <a class="header-anchor" href="#一次访问网站" aria-label="Permalink to &quot;一次访问网站&quot;">​</a></h1><p>这部分是概念扫盲，不深入复杂原理、部署细节和代码。尺度放得简单一点：把网站背后常见的东西认出来，知道它们大概站在哪一层。再遇到 Linux、Nginx、数据库、前端、后端、Kubernetes、监控和发布工具时，就不至于只看到一堆分散的名字。</p><p>一个网站能被打开，背后要解决很多朴素问题：外面的人怎么找到这台服务器，浏览器怎么和服务器说话，页面从哪里来，数据放在哪里，访问的人多了怎么办，机器坏了怎么办，出问题以后去哪里找证据。公网 IP、域名、HTTP、数据库、负载均衡、高可用、容灾、日志和监控，都是围绕这些问题出现的。</p><p>一次网站访问刚好能把这些东西串起来。浏览器打不开、接口超时、页面白屏、登录后一直转圈，表面看都是“网站有问题”，背后可能是域名解析错了，也可能是端口没放行、证书过期、Nginx 转发失败、后端报错、数据库变慢。</p><p>浏览器地址栏里输入 <code>https://www.example.com/docs/index.html</code> 后，浏览器会先把这一串地址拆开：使用 HTTPS，访问的名字是 <code>www.example.com</code>，路径是 <code>/docs/index.html</code>，默认端口是 <code>443</code>。后面的 DNS、IP、端口、HTTP、前端资源、后端接口，都从这串地址开始。</p><h2 id="一、地址栏里的地址" tabindex="-1">一、地址栏里的地址 <a class="header-anchor" href="#一、地址栏里的地址" aria-label="Permalink to &quot;一、地址栏里的地址&quot;">​</a></h2><p>地址栏里的完整地址叫 URL。它有固定格式，里面写着几件事：用什么协议访问，访问哪个名字，连哪个端口，要取哪个路径下的内容。</p><p>以这个地址为例：</p><p><code>https://www.example.com:443/docs/index.html?from=notes#title</code></p><table tabindex="0"><thead><tr><th>部分</th><th>示例</th><th>含义</th></tr></thead><tbody><tr><td>协议</td><td><code>https</code></td><td>用 HTTPS 访问，通信会加密</td></tr><tr><td>域名</td><td><code>www.example.com</code></td><td>这个名字需要先换成 IP 地址</td></tr><tr><td>端口</td><td><code>443</code></td><td>HTTPS 默认端口</td></tr><tr><td>路径</td><td><code>/docs/index.html</code></td><td>要访问的页面或资源位置</td></tr><tr><td>查询参数</td><td><code>from=notes</code></td><td>传给服务端的附加信息</td></tr><tr><td>片段</td><td><code>#title</code></td><td>浏览器跳到页面里的某个位置</td></tr></tbody></table><p>端口经常不会写在地址里。<code>https://www.example.com/docs</code> 看起来没有端口，浏览器仍然会按 HTTPS 默认值连接 <code>443</code>。如果是 <code>http://</code>，默认端口就是 <code>80</code>。</p><p>域名和路径要分开看。DNS 只负责把 <code>www.example.com</code> 这个名字换成 IP，不处理 <code>/docs/index.html</code>。路径是在连接到服务器以后，由 Nginx、Web 服务或后端程序继续处理的。</p><h2 id="二、名字变成-ip" tabindex="-1">二、名字变成 IP <a class="header-anchor" href="#二、名字变成-ip" aria-label="Permalink to &quot;二、名字变成 IP&quot;">​</a></h2><p>计算机之间实际通信靠 IP 地址。域名是给人看的名字，DNS 负责把名字换成 IP。</p><p>访问 <code>www.example.com</code> 时，浏览器和操作系统会去查这个名字对应哪个地址。最后可能拿到一条或多条记录：</p><table tabindex="0"><thead><tr><th>记录</th><th>示例</th><th>含义</th></tr></thead><tbody><tr><td><code>A</code></td><td><code>www.example.com -&gt; 203.0.113.10</code></td><td>域名指向 IPv4 地址</td></tr><tr><td><code>AAAA</code></td><td><code>www.example.com -&gt; 2001:db8::10</code></td><td>域名指向 IPv6 地址</td></tr><tr><td><code>CNAME</code></td><td><code>www.example.com -&gt; cdn.example.net</code></td><td>域名先指向另一个域名</td></tr></tbody></table><p>很多网站前面有 CDN。业务域名不一定直接指向源站服务器，而是先指向 CDN 厂商分配的域名，再由 CDN 返回一个离访问者更近的边缘节点 IP。浏览器看到的仍然是一个 IP 和端口，只是这个 IP 可能属于 CDN。</p><p>域名解析失败时，浏览器常见错误是 <code>DNS_PROBE_FINISHED_NXDOMAIN</code>。这类错误还没走到服务器和 HTTP 层，通常要看域名有没有写错、解析记录有没有配、DNS 缓存是不是还没更新。</p><h2 id="三、连接-ip-和端口" tabindex="-1">三、连接 IP 和端口 <a class="header-anchor" href="#三、连接-ip-和端口" aria-label="Permalink to &quot;三、连接 IP 和端口&quot;">​</a></h2><p>拿到 IP 后，浏览器会连接 <code>IP:端口</code>。HTTPS 常见是 <code>203.0.113.10:443</code>，HTTP 常见是 <code>203.0.113.10:80</code>。</p><p>端口用来区分同一台机器上的不同服务。同一个公网 IP 上可以同时有 SSH、HTTP、HTTPS、数据库代理等服务，访问哪个服务要看端口。</p><table tabindex="0"><thead><tr><th>端口</th><th>常见服务</th></tr></thead><tbody><tr><td><code>22</code></td><td>SSH</td></tr><tr><td><code>80</code></td><td>HTTP</td></tr><tr><td><code>443</code></td><td>HTTPS</td></tr><tr><td><code>3306</code></td><td>MySQL</td></tr><tr><td><code>6379</code></td><td>Redis</td></tr></tbody></table><p>连接建立前会发生 TCP 三次握手。HTTPS 还会继续做 TLS 握手，用证书证明站点身份，并协商加密通信需要的密钥。证书过期、域名和证书不匹配、客户端不信任证书，都会在这一步附近暴露出来。</p><p>端口层面的错误和 DNS 错误不一样。<code>ERR_CONNECTION_REFUSED</code> 通常表示已经到达目标 IP，但目标端口没有服务在监听，或者服务主动拒绝。<code>ERR_CONNECTION_TIMED_OUT</code> 更像是中间没有回应，可能是公网 IP 不通、安全组没放行、防火墙丢包、路由异常，或者目标机器没有接到这个连接。</p><h2 id="四、浏览器发请求" tabindex="-1">四、浏览器发请求 <a class="header-anchor" href="#四、浏览器发请求" aria-label="Permalink to &quot;四、浏览器发请求&quot;">​</a></h2><p>连接建立以后，浏览器才开始发送 HTTP 请求。HTTP 可以理解成浏览器和服务端之间说话的格式：浏览器说“我要这个路径”，服务端回“这是结果”。</p><p>访问 <code>https://www.example.com/docs/index.html</code> 时，请求大概会包含这些信息：</p><table tabindex="0"><thead><tr><th>请求内容</th><th>作用</th></tr></thead><tbody><tr><td>方法</td><td><code>GET</code> 读取资源，<code>POST</code> 提交数据</td></tr><tr><td>路径</td><td>告诉服务端要访问哪个页面或接口</td></tr><tr><td>Host</td><td>告诉入口层这次请求访问的是哪个域名</td></tr><tr><td>Header</td><td>携带浏览器类型、Cookie、认证信息、内容类型等</td></tr><tr><td>Body</td><td>表单、JSON、文件上传这类请求会带请求体</td></tr></tbody></table><p>同一个入口 IP 后面可能挂着多个站点。<code>Host</code> 很重要，因为 Nginx 或网关会根据它判断请求属于哪个站点。比如 <code>www.example.com</code> 走官网，<code>api.example.com</code> 走接口服务，它们可能都经过同一个入口层。</p><p>能拿到 <code>404</code>、<code>500</code>、<code>502</code> 这类 HTTP 状态码，说明请求至少已经进入了 Web 入口或后端链路。DNS 解析失败和端口连接失败，通常还拿不到这些状态码。</p><h2 id="五、请求进服务器" tabindex="-1">五、请求进服务器 <a class="header-anchor" href="#五、请求进服务器" aria-label="Permalink to &quot;五、请求进服务器&quot;">​</a></h2><p>公网请求到达机房或云厂商网络后，通常不会直接落到业务程序。中间可能经过 CDN、WAF、负载均衡、Nginx、Ingress、API 网关，再转给后端应用。</p><p>一个常见入口链路是：</p><div class="mermaid-diagram" data-mermaid-code="flowchart%20LR%0A%20%20Browser%5B%22%E6%B5%8F%E8%A7%88%E5%99%A8%22%5D%0A%20%20DNS%5B%22DNS%22%5D%0A%20%20Edge%5B%22CDN%20%2F%20WAF%22%5D%0A%20%20LB%5B%22%E8%B4%9F%E8%BD%BD%E5%9D%87%E8%A1%A1%22%5D%0A%20%20Nginx%5B%22Nginx%20%2F%20Ingress%22%5D%0A%20%20App%5B%22%E5%90%8E%E7%AB%AF%E5%BA%94%E7%94%A8%22%5D%0A%20%20DB%5B%22%E6%95%B0%E6%8D%AE%E5%BA%93%22%5D%0A%0A%20%20Browser%20--%3E%20DNS%0A%20%20DNS%20--%3E%20Browser%0A%20%20Browser%20--%3E%20Edge%0A%20%20Edge%20--%3E%20LB%0A%20%20LB%20--%3E%20Nginx%0A%20%20Nginx%20--%3E%20App%0A%20%20App%20--%3E%20DB%0A"></div><p>小站点可能只有一台云服务器和一个 Nginx；企业系统可能有 CDN、WAF、负载均衡、Kubernetes Ingress 和多个机房。链路越长，入口能力越多，排查时也要更清楚请求停在哪一层。</p><p>几个常见状态码能帮忙定位方向：</p><table tabindex="0"><thead><tr><th>现象</th><th>常见含义</th></tr></thead><tbody><tr><td><code>404 Not Found</code></td><td>请求到了服务端，但路径没有匹配到页面或接口</td></tr><tr><td><code>401 Unauthorized</code></td><td>没登录，或者认证信息无效</td></tr><tr><td><code>403 Forbidden</code></td><td>识别了身份，但没有权限</td></tr><tr><td><code>500 Internal Server Error</code></td><td>后端程序处理请求时报错</td></tr><tr><td><code>502 Bad Gateway</code></td><td>入口层连接后端失败</td></tr><tr><td><code>503 Service Unavailable</code></td><td>后端暂时不可用，可能实例都不健康或服务过载</td></tr></tbody></table><p><code>500</code> 和 <code>502</code> 容易混。<code>500</code> 多半是后端已经收到请求，但处理时异常。<code>502</code> 更常见于入口层没有连上后端，比如 upstream 地址错了、Pod 没起来、端口配置不一致、后端连接被拒绝。</p><h2 id="六、页面不是一次拿完" tabindex="-1">六、页面不是一次拿完 <a class="header-anchor" href="#六、页面不是一次拿完" aria-label="Permalink to &quot;六、页面不是一次拿完&quot;">​</a></h2><p>服务端处理完请求后，会返回状态码、响应头和响应体。浏览器拿到 HTML 后，开始解析页面结构。</p><p>HTML 里通常还会引用 CSS、JavaScript、图片和字体。浏览器解析到这些资源时，会继续发新的请求。一个网页看起来只打开了一次地址，实际可能产生几十个请求。</p><table tabindex="0"><thead><tr><th>资源</th><th>浏览器拿来做什么</th></tr></thead><tbody><tr><td>HTML</td><td>页面结构</td></tr><tr><td>CSS</td><td>字体、颜色、间距、布局</td></tr><tr><td>JavaScript</td><td>页面交互、调用接口、更新内容</td></tr><tr><td>图片/字体</td><td>页面素材</td></tr><tr><td>API JSON</td><td>动态数据，例如用户信息、列表、统计值</td></tr></tbody></table><p>前后端分离的页面里，第一次请求可能只拿到一个空壳 HTML 和几份静态资源。JavaScript 运行后再请求 <code>/api/tasks</code>、<code>/api/users/me</code> 这类接口，后端返回 JSON，浏览器再把数据填进页面。</p><p>页面加载慢也要拆开看。HTML 慢，可能是入口层、后端渲染或网络延迟；某个 API 慢，重点会转向后端函数、数据库查询、缓存和下游服务；图片和 JS 慢，则可能是静态资源、CDN、缓存策略或文件体积问题。</p><h2 id="七、整条链路" tabindex="-1">七、整条链路 <a class="header-anchor" href="#七、整条链路" aria-label="Permalink to &quot;七、整条链路&quot;">​</a></h2><p>把一次访问压成一条线，大致是这样的：</p><div class="mermaid-diagram" data-mermaid-code="sequenceDiagram%0A%20%20autonumber%0A%20%20participant%20Browser%20as%20%E6%B5%8F%E8%A7%88%E5%99%A8%0A%20%20participant%20DNS%20as%20DNS%E8%A7%A3%E6%9E%90%0A%20%20participant%20Entry%20as%20%E5%85%A5%E5%8F%A3%E5%B1%82%0A%20%20participant%20Web%20as%20Web%E6%9C%8D%E5%8A%A1%0A%20%20participant%20App%20as%20%E5%90%8E%E7%AB%AF%E5%BA%94%E7%94%A8%0A%20%20participant%20DB%20as%20%E6%95%B0%E6%8D%AE%E5%BA%93%0A%0A%20%20Browser-%3E%3EDNS%3A%20%E6%9F%A5%E8%AF%A2%20www.example.com%0A%20%20DNS--%3E%3EBrowser%3A%20%E8%BF%94%E5%9B%9E%20IP%20%E6%88%96%20CDN%20%E8%8A%82%E7%82%B9%20IP%0A%20%20Browser-%3E%3EEntry%3A%20%E8%BF%9E%E6%8E%A5%20IP%3A443%EF%BC%8C%E5%AE%8C%E6%88%90%20TCP%2FTLS%0A%20%20Browser-%3E%3EEntry%3A%20%E5%8F%91%E9%80%81%20HTTP%20%E8%AF%B7%E6%B1%82%0A%20%20Entry-%3E%3EWeb%3A%20%E8%BD%AC%E5%8F%91%E5%88%B0%20Web%20%E6%9C%8D%E5%8A%A1%0A%20%20Web-%3E%3EApp%3A%20%E5%8A%A8%E6%80%81%E8%AF%B7%E6%B1%82%E4%BA%A4%E7%BB%99%E5%90%8E%E7%AB%AF%E5%BA%94%E7%94%A8%0A%20%20App-%3E%3EDB%3A%20%E6%9F%A5%E8%AF%A2%E6%88%96%E5%86%99%E5%85%A5%E6%95%B0%E6%8D%AE%0A%20%20DB--%3E%3EApp%3A%20%E8%BF%94%E5%9B%9E%E6%95%B0%E6%8D%AE%0A%20%20App--%3E%3EWeb%3A%20%E8%BF%94%E5%9B%9E%20HTML%20%E6%88%96%20JSON%0A%20%20Web--%3E%3EBrowser%3A%20%E8%BF%94%E5%9B%9E%E7%8A%B6%E6%80%81%E7%A0%81%E3%80%81%E5%93%8D%E5%BA%94%E5%A4%B4%E3%80%81%E5%93%8D%E5%BA%94%E4%BD%93%0A%20%20Browser-%3E%3EEntry%3A%20%E7%BB%A7%E7%BB%AD%E8%AF%B7%E6%B1%82%20CSS%E3%80%81JS%E3%80%81%E5%9B%BE%E7%89%87%E5%92%8C%20API%0A"></div><p>这条线能把很多技术放回原位：Linux 网络解释 IP、端口、路由和防火墙；Nginx 处理域名、路径和反向代理；前端处理 HTML、CSS、JavaScript 和接口请求；后端处理 HTTP 路由、业务逻辑和数据库；CDN、WAF、负载均衡、Kubernetes Ingress 站在入口层，把公网流量送到真正处理请求的服务上。</p>',48)])])}const l=d(r,[["render",c]]);export{s as __pageData,l as default};
